def validate(args, output):
    words, groups = args[0], args[1]
    if not isinstance(output, list) or not all(isinstance(w, str) for w in output):
        return False
    index_of = {w: i for i, w in enumerate(words)}
    idxs = []
    for w in output:
        if w not in index_of:
            return False
        idxs.append(index_of[w])
    for a, b in zip(idxs, idxs[1:]):
        if b <= a:
            return False
        if groups[a] == groups[b]:
            return False
    max_len = 0
    prev = None
    for g in groups:
        if g != prev:
            max_len += 1
            prev = g
    return len(output) == max_len

