function validate(args, output) {
    const words = args[0], groups = args[1];
    if (!Array.isArray(output) || !output.every(w => typeof w === 'string')) return false;
    const indexOf = new Map(words.map((w, i) => [w, i]));
    const idxs = [];
    for (const w of output) {
        if (!indexOf.has(w)) return false;
        idxs.push(indexOf.get(w));
    }
    for (let k = 0; k + 1 < idxs.length; k++) {
        if (idxs[k + 1] <= idxs[k]) return false;
        if (groups[idxs[k]] === groups[idxs[k + 1]]) return false;
    }
    let maxLen = 0, prev = null;
    for (const g of groups) {
        if (g !== prev) { maxLen++; prev = g; }
    }
    return output.length === maxLen;
}

